#include<bits/stdc++.h>
using namespace std;
int n, flag[100], a[100];
void print() {
    for(int i = 1; i <= n; i++)
        printf("%5d", a[i]);
    printf("\n");
}
void dfs(int k) { 
    if(k>n) {
        print();
        return;
    }
    for(int i = 1; i <= n; i++) {
        if(!flag[i]) { 
            flag[i] = 1;
            a[k]=i;
            dfs(k+1);
            flag[i] = 0;
        }
    }
}
int main() {
    cin >> n;
    dfs(1);
    return 0;
}
